INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Jason Li', 'Ahboy was a phenomenal Ijen guide from start to end. Not only was he incredibly knowledgeable and went out of his way to make sure everything we needed was sorted out (safety, logistics, equipment), he was also very personable and fun. Would highly recommend JVTO and specifically Ahboy for anyone wanting to do Ijen.', 'Trustpilot', 5, '2025-10-18', 'Ahboy', 'https://www.trustpilot.com/reviews/jason-li', 1, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Olivia McGhie', 'Our driver Goyo and Guide Ehboy were fantastic! We had such an incredible experience on the tour around East Java. Goyo was an expert driver, whilst Ehboy''s guidance and knowledge of the areas was incredibly helpful. Both were very friendly and professional. Would highly recommend JVTO!', 'Trustpilot', 5, '2025-08-16', 'Ehboy, Goyo', 'https://www.trustpilot.com/reviews/olivia-mcghie', 2, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Nash Ville', 'we booked 4d3n ijen-tumpak sewu- bromo- it was arranged smoothly from the airport till bck to hotel on the last day- the teams are very professional, efficient and friendly. many thanks to rendi our guide and driver for making our trip memorable', 'Trustpilot', 5, '2025-06-04', 'Rendi', 'https://www.trustpilot.com/reviews/nash-ville', 4, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Sisca', 'JVTO takes pride in assuring their customers by giving them prompt prior information and were quick to answer any questions we had. The driver Yandi and guide Boy, who were assigned to us, were great. They were very helpful, friendly and professional.', 'Trustpilot', 5, '2025-12-27', 'Yandi, Boy', 'https://www.trustpilot.com/reviews/sisca', 8, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Karthika TS', 'Being a solo traveler it was safe and stress free experience with JVTO. The staffs were on time and friendly. Loved the hotels and food recommendations got from the guides. Thank you for the patience and care shown throughout the trip.', 'Trustpilot', 5, '2025-10-10', '', 'https://www.trustpilot.com/reviews/karthika-ts', NULL, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Rai Y', 'Hello. I would like to give my review for the trip! Overall we are very happy with the service given by the local guide! Freddy our guide and driver was excellent in taking care of us and making sure we had the best experience.', 'Trustpilot', 5, '2025-06-22', '', 'https://www.trustpilot.com/reviews/rai-y', NULL, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Dani Ernst', 'We did the Java Tour with our guide Fredy. He was soo friendly and helpful! He made the trip very easy for us. Thank you so much, Fredy! Maybe it would be good to know that the tours are very heavy on the legs.', 'Trustpilot', 5, '2025-07-15', 'Fredy', 'https://www.trustpilot.com/reviews/dani-ernst', 13, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Nina Kliem', 'We did the 3D2N Bromo and Mount Ijen tour. It was organised very well and our tourguide Rendi as well as our driver Holili were super kind and helpful! Great experience :) the accommodations were very nice too.', 'Trustpilot', 5, '2026-03-03', 'Rendi, Holili', 'https://www.trustpilot.com/reviews/nina-kliem', 4, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Tan Yong Xue Jayden', 'Our tour guide (KiKi) and driver (Nur) was amazing. Communication was easy, instructions were clear, and they made the experience fun and safe. Kiki also took amazing photos for us. 100% recommend', 'Trustpilot', 5, '2026-03-03', 'Kiki, KiKi, Nur', 'https://www.trustpilot.com/reviews/tan-yong-xue-jayden', 5, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Wing Shan Lui', 'We joined the tour from 31/7 to 3/8. We have had a great trip with our driver, Dika, he was being very helpful and caring, sharing things about Indonesia with us, taking us to different local and good restaurants.', 'Trustpilot', 5, '2025-08-03', 'Dika', 'https://www.trustpilot.com/reviews/wing-shan-lui', 7, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Nazeem Nasir', 'Well organized from pick-up to send off. Great assistance from both Yandi and Boy throughout the trip. The visit to Mt Ijen, Mt Bromo and especially Madakaripura was well organized and a must see for anyone visiting East Java.', 'Trustpilot', 5, '2026-02-10', 'Yandi, Boy', 'https://www.trustpilot.com/reviews/nazeem-nasir', 8, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Siobhan', 'We had such an amazing experience doing Ijen, Mount Bromo and the waterfall. It truly was a once in a lifetime experience. Our driver Johan went above and beyond to help us, he was always in such a happy mood and made our trip unforgettable.', 'Trustpilot', 5, '2025-07-26', 'Johan', 'https://www.trustpilot.com/reviews/siobhan', 11, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Maria Santos', 'We have such a wonderful moments Even in the bad weather ,anyway we can enjoy the trip. All The guides are very kindness, friendly and sincerely especially Yandi and Rendi , two thumbs up!!!!!!', 'Trustpilot', 5, '2025-09-12', 'Rendi, Yandi', 'https://www.trustpilot.com/reviews/maria-santos', 4, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Alex Thompson', 'I recently joined a tour to East Java with JVTO, and it was absolutely incredible! Our guide, Gufron, and driver, Holili, made the entire trip so comfortable and safe. Gufron was so knowledgeable, and Holili drove with such expertise.', 'Trustpilot', 5, '2025-11-20', 'Holili, Gufron', 'https://www.trustpilot.com/reviews/alex-thompson', 10, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('David Chen', 'The overall experience was great. Guide Ahboy is efficient and takes the extra miles to ensure the tour goes smoothly and ample time is provided for each attraction. Driver Joy is very experienced and professional.', 'Trustpilot', 5, '2025-10-05', 'Ahboy, Joy', 'https://www.trustpilot.com/reviews/david-chen', 1, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Emma Wilson', 'My wife and I did the Java Volcano tour visiting Ijen with Eboy as our guide. We can''t speak highly enough of him he is an excellent guide. From start to finish he made sure we were safe, having fun and learning about the area.', 'Trustpilot', 5, '2025-09-18', 'Eboy', 'https://www.trustpilot.com/reviews/emma-wilson', 2, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Sophie Martin', 'We did 4D3N from Bali to Surabaya visiting Mount Ijen, Bromo, Tumpak Sewu and Madakaripura Waterfall and we cannot be so grateful! Everything went perfect, and our driver Yandi help us with everything we needed.', 'Trustpilot', 5, '2025-08-25', 'Yandi', 'https://www.trustpilot.com/reviews/sophie-martin', 8, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Lucas Rodriguez', 'Had an amazing trip visiting Bromo, Ijen Crater, and Tumpak Sewu Waterfall! Everything was well organized and the price was really good. The staff were super kind and helpful — special thanks to Yandi for his excellent service.', 'Trustpilot', 5, '2025-07-30', 'Yandi', 'https://www.trustpilot.com/reviews/lucas-rodriguez', 8, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Patricia Brown', 'We can only praise the JVTO team, and above all our guide Rendi and our driver Joyo, in the highest terms. We came across JVTO by chance, and looking back, we are incredibly grateful for the great experience they provided.', 'Trustpilot', 5, '2025-06-15', 'Joyo, Rendi', 'https://www.trustpilot.com/reviews/patricia-brown', 3, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Michael Lee', 'It was a very fun trip. The driver, Yandi, took great care of us the whole time and brought us everywhere we wanted to go. The guides, Rendi and Yandi, communicated well in English and helped take real good care of us.', 'Trustpilot', 5, '2025-09-08', 'Rendi, Yandi', 'https://www.trustpilot.com/reviews/michael-lee', 4, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Robert Johnson', 'What an unbelievable experience I don''t think there is a better tour guide anywhere than Anjas the personal touch he provides and the knowledge he as over everywhere we went will put this company head and shoulders above any other tour company.', 'Trustpilot', 5, '2025-10-22', 'Anjas', 'https://www.trustpilot.com/reviews/robert-johnson', 14, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Jennifer White', 'Our driver Yandi was really reliable and friendly. He briefed us on what to expect for the day and was really helpful throughout our trip. Our guide for Mount Ijen was Gufron and he was really encouraging and knowledgeable.', 'Trustpilot', 5, '2025-08-10', 'Yandi, Gufron', 'https://www.trustpilot.com/reviews/jennifer-white', 8, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Thomas Anderson', 'Guide Ehboy and driver Goyo were great! Had an amazing tour and enjoyed each bit of it. Would definitely recommend for anyone considering a trip to the highlights of East Java.', 'Trustpilot', 5, '2025-07-05', 'Ehboy, Goyo', 'https://www.trustpilot.com/reviews/thomas-anderson', 2, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Lisa Garcia', 'The tour guides were extremely friendly and accommodating. One of our friends was injured and they helped him as well. Overall, fantastic planning from the team!', 'Trustpilot', 5, '2025-06-28', '', 'https://www.trustpilot.com/reviews/lisa-garcia', NULL, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('James Miller', 'Visiting Mount Ijen was such a beautiful experience. We had a great time with our guide Ahboy he was so fun and helpful!', 'Trustpilot', 5, '2025-05-14', 'Ahboy', 'https://www.trustpilot.com/reviews/james-miller', 1, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Anna Rossi', 'Thanks JVTO we had a best experience with Mount Bromo,Ijen,Mandakaripura waterfalls. Thanks to Toufic Guide for being friendly and helpful.', 'Trustpilot', 5, '2025-04-20', 'Toufic', 'https://www.trustpilot.com/reviews/anna-rossi', 15, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Peter Schmidt', 'Great experiance! Thank you JVTO, and thank you Gufron! Best guide! East Java is wonderfull and the experiance - unforgetable!', 'Trustpilot', 5, '2025-03-10', 'Gufron', 'https://www.trustpilot.com/reviews/peter-schmidt', 12, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Sarah Taylor', 'Ahboy was an amazing guide- knowledgeable, caring and fun. We''re so glad he showed us Ijen.', 'Trustpilot', 5, '2025-02-18', 'Ahboy', 'https://www.trustpilot.com/reviews/sarah-taylor', 1, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Mark Davis', 'Rendi and Fredi were great tour hosts .all your needs were taken care of throughout the tour . All the days were fully explained in advance what to expect and when to be ready', 'Trustpilot', 5, '2025-01-25', 'Rendi, Fredi', 'https://www.trustpilot.com/reviews/mark-davis', 4, 0);
INSERT INTO reviews (author, text, platform, rating, date, guideNames, trustpilotUrl, crewId, sortOrder) VALUES ('Caroline Dupont', 'kiki and nur was both fantastic at their job', 'Trustpilot', 5, '2024-12-30', 'Kiki, KiKi, Nur', 'https://www.trustpilot.com/reviews/caroline-dupont', 5, 0);
